var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"당신 제정신이야? 그 분홍 쓰레기랑 마주쳤으면 어쩔 뻔했어?","JPN":"あなた正気なの？　あのピンク色のクズとばったり会ったら大変なことになってたはずよ？","ENG":"Have you lost your mind? What would you have done if you ran into that pink scumbag?","TWN":"你腦袋沒問題吧？萬一遇到那個粉紅垃圾怎麼辦？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"속여서 미안해. 그래도 결과적으로는 잘 해결됐잖아.","JPN":"騙してごめん。でも結果的にはうまく行ったでしょう。","ENG":"I’m sorry for deceiving you. But everything worked out in the end.","TWN":"抱歉，瞞著你，但就結果而言應該算是順利解決吧？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그래요. 덕분에 저는 레버넌트 씨가 망가뜨린 부품 다시 끼우느라 진땀 뺐고요.","JPN":"ですね。おかげさまで私はレヴナントさんが壊した部品をどうにか組み立て直そうとすごく焦りました。","ENG":"Oh really. I’ve been all over the place trying to fix everything Revenant broke.","TWN":"是啊，為了把你弄壞的零件裝回去，搞得我滿頭大汗，這都是拜你所賜呢。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"고생시킨 값으로 홍차에 대해 알려 줄게. 좋은 가게를 몇 군데 알고 있어.","JPN":"そのお代で紅茶について教えてあげる。いい店をいくつか知ってるから。","ENG":"I’ll teach you all about black tea as an apology for your trouble. I know some good places.","TWN":"那我就帶你認識紅茶的世界作為補償吧，我是知道幾家不錯的店啦。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런 이야기는 일 다 끝난 다음에 해요.","JPN":"そんな話は仕事が終わった後にしてください。","ENG":"Let’s talk about that after it’s actually done.","TWN":"這種話等整件事落幕後再說吧。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"전선 나가서 나중에 어쩌고, 저쩌고 하던 인간들 전부 머리에 구멍 났거든요.","JPN":"前線で、戦争が終わったらって、なんやかんや言っていた人はみんな頭に風穴が空きましたからね。","ENG":"So many people have said stuff like that before heading out to the front and ended up with bullets in their heads.","TWN":"那些在戰場上說等打完後怎樣怎樣的人，沒有一個活著回來的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"걱정해 주는 거야?","JPN":"心配してくれるの？","ENG":"Are you worried about me?","TWN":"你是在擔心我嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"당연하죠. 고향에 부양 가족만 셋인데 아주머니까지 얹는다고 상상해 보세요.","JPN":"当たり前です。故郷に養う家族だけでも三人なのに、おばさんまで引き受けたらどうなると思いますか？","ENG":"Of course I am. I already have three dependents in my hometown. Don’t want to add an elderly person on top of that.","TWN":"那當然！我家裡上有高堂要養，要是再加上伯母，你能想像嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"기왕 얹는 거 나도 얹어 주면 안 돼?","JPN":"引き受けるなら、私も引き受けてもらえない？","ENG":"Well, since you’re already thinking about taking care of them, mind taking care of me too?","TWN":"既然都要養，那乾脆多養我一個吧？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저어어얼대 싫습니다!","JPN":"絶ーーっ対嫌です！","ENG":"Not a SINGLE chance!","TWN":"絕對～～～～不要！"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……? 손님, 이걸로 딸아이랑 얘기할 수 있어요?","JPN":"へえ……？　お客さん、これで娘と話せますか？","ENG":"Huh...? Can I talk to my daughter with this?","TWN":"嗯……？用這個就可以跟女兒說話嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아, 아주머니. 그거 건드리시면 안 되는데…….","JPN":"あ、おばさん。それ触っちゃダメなんですが……","ENG":"M-madam, you shouldn't touch that...","TWN":"伯母，那個不能碰啦……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아……. 우리 딸, 들리니……?","JPN":"レア……私の娘、聞こえてるの……？","ENG":"Leah... My daughter, can you hear me...?","TWN":"蕾亞……女兒有聽到嗎……？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"네. 엄마. 아주 잘 들려요.","JPN":"はい、お母さん。よく聞こえているよ。","ENG":"Yes. Mom. I can hear you fine.","TWN":"嗯，媽，我有聽到。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"가서 하려던 일은 잘 끝났어……?","JPN":"仕事は無事に終わった……？","ENG":"Did you finish what you went out to do...?","TWN":"你事情辦得還順利嗎……？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……아직 하고 있는 중이에요.","JPN":"……まだ終わっていない。","ENG":"...I’m still in the middle of finishing it.","TWN":"……還在進行中呢。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래도 걱정 마세요. 전부 잘 끝날 거예요.","JPN":"でも心配しないで。全部うまく行くから。","ENG":"Still, don’t worry. Everything will be okay.","TWN":"不過媽別擔心，會順利結束的。"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L23_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……. 그렇구나…….","JPN":"うん……そうなのね……","ENG":"H-huh... I see...","TWN":"嗯嗯……那就好……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"엄마. 나 하나만 물어 봐도 돼요?","JPN":"お母さん。一つ聞いてもいい？","ENG":"Mom. Can I ask a question?","TWN":"媽，我可以問你一件事嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그럼……. 물론이지…….","JPN":"ええ……もちろんよ……","ENG":"Yes... Of course...","TWN":"當然……可以……"},"stage":{"bg":"WINTER_STREET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"내가 사람이 아니더라도……. 나는 엄마 딸이지?","JPN":"私が人間でなくでも……私はお母さんの娘だよね？","ENG":"Even if I’m not a human being... I’m your daughter, right?","TWN":"就算我不是人……但我還是媽的女兒吧？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아야…….","JPN":"レア……","ENG":"Leah...","TWN":"蕾亞……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"불이 아주 크게 났어…….","JPN":"大きな火事が起きたの……","ENG":"There was a big fire...","TWN":"那時候火好大……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"사람들이 많이, 그러니까……. 아주 많이 죽었단다…….","JPN":"人々がたくさん、えっと……とてもたくさん死んだのよ……","ENG":"A lot of people, well... Quite a lot of people died...","TWN":"有好多人……好多人死掉……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"정신을 차려 보니 너도 피투성이가 되어서……. 아무리 불러도 대답이 없어서…….","JPN":"気が付けばあなたも血まみれになって……いくら呼んでも返事がなくて……","ENG":"By the time I pulled myself together, you were covered in blood... And no matter how many times I said your name, you didn’t answer...","TWN":"等我回過神來，發現你也傷得很重……不管我怎麼叫你，你都沒反應……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"방금 전까지 또 연주를 들으러 오자고 하던 네가 아무말도 없어서…….","JPN":"ついさっきまで、また演奏を聞きたいと言っていたあなたが何も言わなくて……","ENG":"Not just a few moments before, you were asking me to come with you to listen to the performance, but then all of a sudden, you couldn’t say anything...","TWN":"上一秒你才跟我說下次還要來聽演奏會，下一秒卻不省人事……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"엄마는 굉장히 슬펐던 것 같아…….","JPN":"お母さん、とても悲しかった気がするよ……","ENG":"I was devastated...","TWN":"媽那時候真的很難過……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그 때……. 검은 옷을 입은 천사님이 나타나셨단다…….","JPN":"その時……黒い服を着た天使が舞い降りたの……","ENG":"Then... An angel in black appeared...","TWN":"突然……有一個穿著黑衣的天使出現……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"지치고 힘들어 보였지만……. 그런데도 예쁜 목소리로 말씀하셨지…….","JPN":"疲れて、苦しそうに見えたけど……それなのにきれいな声でおっしゃった……","ENG":"She looked exhausted... But still her voice was so beautiful...","TWN":"她看起來很疲憊的樣子……不過她的聲音很好聽……"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"CONDUCT_HARMONY_NULL_NULL","text":{"KOREA":"거래를 하죠.","JPN":"取引をしましょう。","ENG":"Let us make a pact.","TWN":"我們來交易吧。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_HEARTBEAT"},{"id":"L2_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"너를 살려 주는 대신에……. 소중하게 키워 달라고.","JPN":"あなたを助ける代わりに……大事に育てなさいって。","ENG":"In return for saving your life... she asked me to raise you the best I could.","TWN":"她說她可以讓你起死回生……條件是以後要好好把你養大。"},"stage":{"bg":"BLACK","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CONDUCT_HARMONY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"……고마워, 엄마. 솔직하게 얘기해 줘서.","JPN":"……ありがとう、お母さん。正直に話してくれて。","ENG":"...Thanks, Mom. For telling me the truth.","TWN":"……媽，謝謝你願意跟我說實話。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L7_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"으응……. 아니야…….","JPN":"ううん……そんなことないよ。","ENG":"Yeah… It's nothing…","TWN":"嗯嗯……別這麼說……"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"항상 힘들게 해서……. 미안하구나.","JPN":"いつも苦労かけて……ごめんなさいね。","ENG":"I’m sorry... for always making things hard for you.","TWN":"是媽對不起你……讓你這麼辛苦。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"RIFLE_ADMIN_NAMED_NULL","text":{"KOREA":"부전대장님, 미약하지만 건국기념전당 지하에서 구 관리국의 식별신호가 잡혔습니다!","JPN":"副戦隊長、弱いですが建国記念館の地下で旧管理局の識別信号が捉えられました！","ENG":"Deputy Commander, we’re picking up a very weak Old Administration identification signal from the basement of National Foundation Hall!","TWN":"副戰隊長，在建國紀念堂地下室發現舊管理局的識別訊號！不過訊號有點微弱。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIFLE_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"가족과의 대화 중에 미안하지만……","JPN":"家族との話し中に割り込んで悪いけど……","ENG":"I’m sorry to interrupt your family talk but...","TWN":"不好意思，打斷你們母女的對話……"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"들었지, 레버넌트 씨? 당신 직감이 맞았어.","JPN":"聞いたよね、レヴナントさん？　あなたの感が当たっていた。","ENG":"You hear that Revenant? Your gut feeling was right.","TWN":"亡靈，你有聽到吧？你的直覺是對的。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"그래. 자크의 부하들은 눈속임이었다는 거지.","JPN":"そう。ジャックの部下たちは目くらましだったというわけ。","ENG":"Yeah, well. Jacques’ men were just decoys.","TWN":"嗯嗯，札克的手下只是障眼法對吧？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 폭발인지는 어떻게 짐작한 거야?","JPN":"でも、爆発はどうやって推測したの？","ENG":"But how did you know about the explosives?","TWN":"不過你怎麼會猜到有爆裂物？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"폭발 사고가 그림자 때문이었다는 얘기를 듣고.","JPN":"爆発事故がシャドウの仕業だったという話を聞いてね。","ENG":"I heard the explosion incident was because of a Shadow.","TWN":"在聽到爆炸事件是暗影所為後，"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"<color=#ffd34c>네가 저지른 건 이런 만행이었다</color>라는 식으로 과시하기에 안성맞춤이잖아.","JPN":"<color=#ffd34c>お前の犯したことはこういう蛮行だった</color>という風に見せつけるには打ってつけでしょ？","ENG":"It’s the perfect way to show off <color=#ffd34c>‘What you did was an atrocity.’</color>.","TWN":"我就想，他們一定會<color=#ffd34c>趁機借刀殺人</color>，把罪都推到暗影頭上。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그래. 섬뜩하지만 좋은 발상이야.","JPN":"なるほど。ぞっとするけど、いい発想ね。","ENG":"Okay. It’s a terrifying but good idea.","TWN":"嗯嗯，雖然有點驚人，不過你的想法是對的。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……그런데, 이 나라는 중요 인사들이 모이는 건물 보안을 그렇게 허술하게 해 놓나?","JPN":"……でも、この国って重要人事が集まる建物のセキュリティーをそんなに適当にしておくの？","ENG":"...But, does this country really have such terrible security around a building with so many important people?","TWN":"……不過那個地方有這麼多重要的人士聚集，戒備會這麼鬆散嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_NULL_NULL","text":{"KOREA":"글쎄. 20년쯤 알람 대신 총소리 듣고 깨는 우리나라 명물이라고 할까.","JPN":"さあね。20年ぐらい目覚まし代わりに銃声を聞いて起きる、我が国の名物ってところかな。","ENG":"Well. It’s been normal to wake up to gunshots rather than alarm clocks for about 20 years in this country.","TWN":"這個嘛，畢竟這20年來，我們都是被槍聲代替鬧鐘聲叫醒的，這算是我們國家的特色嗎？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"그럼 연락은 여기까지. 나도 곧 도착할 예정이야.","JPN":"では、連絡はこの辺で。私ももうすぐ到着する予定だよ。","ENG":"Anyways, I’m ending communication. I’m about to arrive too.","TWN":"先這樣吧，我就快到了。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"흐음, 혹시 지각하지는 않겠어?","JPN":"ふむ、もしかして遅刻したりはしないよね？","ENG":"Hmm... Aren’t you going to be too late?","TWN":"嗯嗯，你應該不會遲到吧？"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WITH_BIKE","text":{"KOREA":"걱정이 많네. 당연히 제때 도착해야지.","JPN":"心配性だね。間に合って当然でしょう。","ENG":"Stop worrying so much. I’ll be there on time.","TWN":"擔心很多欸，我會準時抵達的。"},"stage":{"bg":"WINTER_STREET","bgm":"THEMA_SECURITY_AGENT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WITH_BIKE","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};